sql:
SELECT COUNT(DISTINCT user_id)
FROM user_access
WHERE stock_id = (SELECT stock_id FROM stocks WHERE stock_symbol = 'AAPL');

external_knowledge:
'top predictors' refers to users with the highest average accuracy of price predictions for technology stocks;
'tech world' refers to the Technology sector;
'price guesses' are price predictions in the database;

sql:
SELECT COUNT(*)
FROM (
  SELECT DISTINCT user_id FROM reports
  INTERSECT
  SELECT DISTINCT user_id FROM user_access
);

SELECT COUNT(*) 
FROM visualizations 
WHERE shared_with IS NOT NULL;

SELECT user_id, COUNT(visualization_id) AS total_visualizations
FROM visualizations
GROUP BY user_id;

SELECT DISTINCT stock_symbol 
FROM stocks 
WHERE country = 'United States';
